class Solution:
    def maxSumOfThreeSubarrays(self, nums, k):
        n = len(nums)
        pre = [0]
        for v in nums:
            pre.append(pre[-1] + v)
        def w(i):
            return pre[i + k] - pre[i]
        starts = list(range(0, n - k + 1))
        best = None
        best_tuple = None
        for i in starts:
            for j in range(i + k, n - k + 1):
                for l in range(j + k, n - k + 1):
                    s = w(i) + w(j) + w(l)
                    cand = (i, j, l)
                    if best is None or s > best or (s == best and cand < best_tuple):
                        best = s
                        best_tuple = cand
        return list(best_tuple)

