class Solution:
    def maxSumOfThreeSubarrays(self, nums, k):
        n = len(nums)
        pre = [0]
        for v in nums:
            pre.append(pre[-1] + v)
        m = n - k + 1
        wsum = [pre[i + k] - pre[i] for i in range(m)]
        left = [0] * m
        best = 0
        for i in range(m):
            if wsum[i] > wsum[best]:
                best = i
            left[i] = best
        right = [0] * m
        best = m - 1
        for i in range(m - 1, -1, -1):
            if wsum[i] >= wsum[best]:
                best = i
            right[i] = best
        ans = None
        ans_sum = -1
        for j in range(k, m - k):
            l = left[j - k]
            r = right[j + k]
            total = wsum[l] + wsum[j] + wsum[r]
            if total > ans_sum:
                ans_sum = total
                ans = [l, j, r]
        return ans

