var maxSumOfThreeSubarrays = function(nums, k) {
    const n = nums.length;
    const pre = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) pre[i + 1] = pre[i] + nums[i];
    const m = n - k + 1;
    const wsum = new Array(m);
    for (let i = 0; i < m; i++) wsum[i] = pre[i + k] - pre[i];
    const left = new Array(m);
    let best = 0;
    for (let i = 0; i < m; i++) {
        if (wsum[i] > wsum[best]) best = i;
        left[i] = best;
    }
    const right = new Array(m);
    best = m - 1;
    for (let i = m - 1; i >= 0; i--) {
        if (wsum[i] >= wsum[best]) best = i;
        right[i] = best;
    }
    let ans = null;
    let ansSum = -1;
    for (let j = k; j < m - k; j++) {
        const l = left[j - k];
        const r = right[j + k];
        const total = wsum[l] + wsum[j] + wsum[r];
        if (total > ansSum) {
            ansSum = total;
            ans = [l, j, r];
        }
    }
    return ans;
};
